    pv_power:               pv,
    home_power:             home,
    grid_import_power:      gridImport,
    grid_export_power:      gridExport,
    battery_charge_power:   battCharge,
    battery_discharge_power: battDischarge,
    battery_power_net:      battNet
};

for (const [k, v] of Object.entries(vals)) {
    node.send({ topic: 'solarwatt/' + k, payload: String(v), retain: true, qos: 0 });
}
return null;

function findItem(items, name) {
  return items.find(i => i.name === name);
}

function parseNumber(raw) {
  if (raw === null || raw === undefined) return null;
  let s = String(raw).trim();
  if (!s) return null;
  if (s.includes('|')) s = s.split('|')[1].trim();
  s = s.split(' ')[0].replace(',', '.');
  const n = Number(s);
  return Number.isFinite(n) ? n : null;
}

let items;
